def encode(message):
    vowels = 'aeiouAEIOU'
    result = []

    for char in message:
        if char.isalpha():
            # Swap case
            swapped_char = char.lower() if char.isupper() else char.upper()

            # Replace vowels with letter 2 places ahead
            if swapped_char in vowels:
                if swapped_char.islower():
                    # For lowercase vowels
                    new_char = chr((ord(swapped_char) - ord('a') + 2) % 26 + ord('a'))
                else:
                    # For uppercase vowels
                    new_char = chr((ord(swapped_char) - ord('A') + 2) % 26 + ord('A'))
                result.append(new_char)
            else:
                result.append(swapped_char)
        else:
            # Keep spaces and other non-letter characters
            result.append(char)

    return ''.join(result)
